+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {kind: 'fixed'; value: number}
+	| {kind: 'fr'; value: number}
+	| {kind: 'auto'}
+	| {kind: 'minmax'; min: number; max: number | undefined};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+	const tokens = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.flatMap(token => {
+		if (token === 'auto') return [{kind: 'auto'}];
+		const fraction = /^(\\d*\\.?\\d+)fr$/.exec(token);
+		if (fraction) return [{kind: 'fr', value: Number(fraction[1])}];
+		if (/^\\d*\\.?\\d+$/.test(token)) return [{kind: 'fixed', value: Number(token)}];
+		const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+)(?:fr)?\\s*\\)$/.exec(token);
+		if (!minmax) return [];
+		const maxIsFr = /fr\\s*\\)$/.test(token);
+		return [{kind: 'minmax', min: Number(minmax[1]), max: maxIsFr ? Number(minmax[2]) : undefined}];
+	});
+};
+
+const placement = (value: number | string | undefined): [number | undefined, number | undefined] => {
+	if (typeof value === 'number') return [value - 1, value];
+	if (!value) return [undefined, undefined];
+	const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+	return match ? [Number(match[1]) - 1, Number(match[2]) - 1] : [undefined, undefined];
+};
+
+const sizes = (tracks: Track[], available: number, gap: number, auto: number[]): number[] => {
+	const result = tracks.map((track, index) => track.kind === 'fixed' ? track.value : track.kind === 'minmax' ? track.min : track.kind === 'auto' ? (auto[index] ?? 0) : 0);
+	const remaining = Math.max(0, available - result.reduce((sum, size) => sum + size, 0) - gap * Math.max(0, tracks.length - 1));
+	const totalFr = tracks.reduce((sum, track) => sum + (track.kind === 'fr' ? track.value : track.kind === 'minmax' ? (track.max ?? 0) : 0), 0);
+	if (totalFr > 0) {
+		for (const [index, track] of tracks.entries()) {
+			const fraction = track.kind === 'fr' ? track.value : track.kind === 'minmax' ? (track.max ?? 0) : 0;
+			result[index] += remaining * fraction / totalFr;
+		}
+	}
+	return result;
+};
+
+export const layoutGrid = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') layoutGrid(child as DOMElement);
+	}
+	if (node.style.display !== 'grid' || !node.yogaNode) return;
+
+	const children = node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+	let columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) columns = [{kind: 'auto'}];
+	let rows = parseTracks(node.style.gridTemplateRows);
+	const placements: Array<{child: DOMElement; column: [number | undefined, number | undefined]; row: [number | undefined, number | undefined]}> = [];
+	let nextColumn = 0;
+	let nextRow = 0;
+	for (const child of children) {
+		let column = placement(child.style.gridColumn);
+		let row = placement(child.style.gridRow);
+		if (column[0] === undefined) {
+			column = [nextColumn, nextColumn + 1];
+			nextColumn = (nextColumn + 1) % columns.length;
+			if (nextColumn === 0) nextRow++;
+		}
+		if (row[0] === undefined) row = [nextRow, nextRow + 1];
+		placements.push({child, column, row});
+	}
+	const rowCount = Math.max(0, ...placements.map(item => item.row[1] ?? 0));
+	while (rows.length < rowCount) rows.push({kind: 'auto'});
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const autoColumns = columns.map((_, index) => Math.max(0, ...placements.filter(item => item.column[0] === index && item.column[1] === index + 1).map(item => item.child.yogaNode!.getComputedWidth())));
+	const autoRows = rows.map((_, index) => Math.max(0, ...placements.filter(item => item.row[0] === index && item.row[1] === index + 1).map(item => item.child.yogaNode!.getComputedHeight())));
+	const columnSizes = sizes(columns, node.yogaNode.getComputedWidth(), columnGap, autoColumns);
+	const rowSizes = sizes(rows, node.yogaNode.getComputedHeight(), rowGap, autoRows);
+	const x = [0]; for (const size of columnSizes) x.push(x.at(-1)! + size + columnGap);
+	const y = [0]; for (const size of rowSizes) y.push(y.at(-1)! + size + rowGap);
+	for (const {child, column, row} of placements) {
+		const [columnStart, columnEnd] = column as [number, number];
+		const [rowStart, rowEnd] = row as [number, number];
+		const yogaNode = child.yogaNode!;
+		yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		yogaNode.setPosition(Yoga.EDGE_LEFT, x[columnStart] ?? 0);
+		yogaNode.setPosition(Yoga.EDGE_TOP, y[rowStart] ?? 0);
+		yogaNode.setWidth((x[columnEnd] ?? x.at(-1)!) - (x[columnStart] ?? 0) - columnGap);
+		yogaNode.setHeight((y[rowEnd] ?? y.at(-1)!) - (y[rowStart] ?? 0) - rowGap);
+	}
+	if (node.style.height === undefined) node.yogaNode.setHeight(Math.max(0, y.at(-1)! - rowGap));
+};
